      p_source         => 
'DECLARE

    v_exists NUMBER;

BEGIN

    SELECT COUNT(*)

    INTO v_exists

    FROM USER_PROGRESS

    WHERE ID_INSCRIPCION = :id_inscripcion
    AND MISSION_ID = :mission_id;

    IF v_exists = 0 THEN

        INSERT INTO USER_PROGRESS (

            ID_INSCRIPCION,

            MISSION_ID,

            PROGRESS_PERCENT,

            IS_COMPLETED,

            TOTAL_XP_EARNED,

            TOTAL_MESSAGES,

            TOTAL_TIME_MINUTES,

            STATUS,

            CREATED_AT,

            UPDATED_AT

        )

        VALUES (

            :id_inscripcion,

            :mission_id,

            0,

            ''N'',

            0,

            0,

            0,

            ''IN_PROGRESS'',

            SYSTIMESTAMP,

            SYSTIMESTAMP
        );

    END IF;

    COMMIT;

    APEX_JSON.OPEN_OBJECT;

    APEX_JSON.WRITE(
        ''success'',
        TRUE
    );

    APEX_JSON.CLOSE_OBJECT;

EXCEPTION

    WHEN OTHERS THEN

        ROLLBACK;

        APEX_JSON.OPEN_OBJECT;

        APEX_JSON.WRITE(
            ''success'',
            FALSE
        );

        APEX_JSON.WRITE(
            ''error'',
            SQLERRM
        );

        APEX_JSON.CLOSE_OBJECT;

END;'
      );
