      p_comments       => NULL,
      p_source         => 
'SELECT
    COUNT(*) AS TOTAL_MISSIONS,

    SUM(
        CASE
            WHEN IS_COMPLETED = ''Y''
            THEN 1
            ELSE 0
        END
    ) AS COMPLETED_MISSIONS,

    NVL(
        SUM(TOTAL_XP_EARNED),
        0
    ) AS TOTAL_XP,

    NVL(
        SUM(TOTAL_TIME_MINUTES),
        0
    ) AS TOTAL_TIME,

    ROUND(
        AVG(PROGRESS_PERCENT),
        0
    ) AS AVG_PROGRESS,

    ROUND(
        AVG(PRONUNCIATION_SCORE),
        1
    ) AS AVG_PRONUNCIATION,

    ROUND(
        AVG(GRAMMAR_SCORE),
        1
    ) AS AVG_GRAMMAR,

    FLOOR(
        NVL(
            SUM(TOTAL_XP_EARNED),
            0
        ) / 200
    ) + 1 AS "LEVEL",

    -- CORREGIDO: Se quitaron los par�ntesis exteriores innecesarios
    (
        FLOOR(
            NVL(
                SUM(TOTAL_XP_EARNED),
                0
            ) / 200
        ) + 1
    ) * 200 AS XP_NEXT_LEVEL

FROM USER_PROGRESS
WHERE ID_INSCRIPCION = :id_inscripcion'
      );
