      p_comments       => NULL,
      p_source         => 
'BEGIN

    UPDATE USER_PROGRESS

    SET

        PROGRESS_PERCENT =
            :progress_percent,

        TOTAL_XP_EARNED =
            :total_xp_earned,

        TOTAL_MESSAGES =
            :total_messages,

        TOTAL_TIME_MINUTES =
            :total_time_minutes,

        GRAMMAR_SCORE =
            :grammar_score,

        PRONUNCIATION_SCORE =
            CASE
                WHEN :pronunciation_score IS NOT NULL
                THEN ROUND(
                    (NVL(PRONUNCIATION_SCORE, 0) + :pronunciation_score) / 2,
                    1
                )
                ELSE PRONUNCIATION_SCORE
            END,

        /*
        Mission completion
        */
        IS_COMPLETED =
            CASE
                WHEN :progress_percent >= 100
                THEN ''Y''
                ELSE IS_COMPLETED
            END,

        STATUS =
            CASE
                WHEN :progress_percent >= 100
                THEN ''COMPLETED''
                ELSE STATUS
            END,

        COMPLETED_AT =
            CASE
                WHEN :progress_percent >= 100
                THEN SYSTIMESTAMP
                ELSE COMPLETED_AT
            END,

        LAST_ACTIVITY =
            SYSTIMESTAMP,

        UPDATED_AT =
            SYSTIMESTAMP

    WHERE ID_INSCRIPCION =
        :id_inscripcion

    AND MISSION_ID =
        :mission_id;

    COMMIT;

    APEX_JSON.OPEN_OBJECT;

    APEX_JSON.WRITE(
        ''success'',
        TRUE
    );

    APEX_JSON.CLOSE_OBJECT;

END;'
